import { useNavigate } from "react-router-dom";
import { useState,useEffect  } from "react";
import { hover } from "@testing-library/user-event/dist/hover";

function Parcial2() {
  const navigate = useNavigate();
  const [mostrarModal,setMostrarModal]=useState(false);
  const [animar, setAnimar] = useState(false);
  const [metodoActivo, setMetodoActivo] = useState(null);
  const [hovered, setHovered] = useState(null);
  const informacion = {
  cascada: {
    titulo: "Modelo Cascada",
    imagen: `${process.env.PUBLIC_URL}/img/cascada.png`
  },
  modelo_v: {
    titulo: "Modelo V",
    imagen: `${process.env.PUBLIC_URL}/img/modelo_v.png`
  },
  agiles: {
    titulo: "Metodologías Ágiles",
    imagen: `${process.env.PUBLIC_URL}/img/agiles.png`
  },
  scrum: {
    titulo: "Scrum",
    imagen: `${process.env.PUBLIC_URL}/img/scrum.png`
  },
  kanban: {
    titulo: "Kanban",
    imagen: `${process.env.PUBLIC_URL}/img/kanvan.png`
  },
  xp: {
    titulo: "Extreme Programming",
    imagen: `${process.env.PUBLIC_URL}/img/xp.png`
  },
  hibridas: {
    titulo: "Metodologías Híbridas",
    imagen: `${process.env.PUBLIC_URL}/img/hibreidas_modernas.png`
  }
};

  useEffect(() => {
    if (mostrarModal) {
      setTimeout(() => setAnimar(true), 10);
    }
  }, [mostrarModal]);

  const cerrarModal = () => {
    setAnimar(false);
    setTimeout(() => setMostrarModal(false), 300);
  };

  // Estilos rápidos en línea para visualización
  const estilos = {
    contenedor: { width: '1100px', margin: '50px auto', padding: '20px', textAlign: 'center', fontFamily: 'Arial' },
    pantalla: { width: '100%', height: '50px', backgroundColor: '#f4f4f4', marginBottom: '10px', textAlign: 'right', padding: '10px', boxSizing: 'border-box', fontSize: '1.2rem' },
    grid: { display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '10px' },
    boton: {width: 250,margin:'10px 8px', padding: '12px 15px', cursor: 'pointer', border: 'none', borderRadius: '5px' },
    botonAzul: {backgroundColor: 'white',cursor:"pointer", color: '#0d6efd', borderRadius:"5px", borderColor:"#0d6efd",padding:"12px 30px"},
    modalOverlay: { 
      position: 'fixed',
      top: 0,
      left: 0,
      width: '100%',
      height: '100%',
      backgroundColor: 'rgba(0,0,0,0.7)',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center'
    },
    contenidoModal: {
      backgroundColor: 'white',
      padding: '20px',
      borderRadius: '10px',
      width: '50%',
      transition: 'all 0.6s ease',
      transform: animar ? 'translateY(0)' : 'translateY(-200px)',
      opacity: animar ? 1 : 0
    },
    cerrarX: {
      position: 'absolute',
      top: '10px',
      right: '15px',
      cursor: 'pointer',
      fontWeight: 'bold',
      fontSize: '20px'
    }
  };
  return (
    <div style={estilos.contenedor}>
      <h1>METODOLOGÍAS DE DESARROLLO DE SW</h1>
      <h2>¿Qué es una metodología de desarrollo de software?</h2>
      <p style={estilos.texto}>Las metodologías de desarrollo de software son un conjunto de técnicas y métodos organizativos que se aplican para diseñar soluciones de software informático. El objetivo de las distintas metodologías es el de intentar organizar los equipos de trabajo para que estos desarrollen las funciones de un programa de la mejor manera posible.</p>
      <h1>TIPOS DE METODOLOGÍAS</h1>
      <hr style={{marginTop:100}}></hr>

        <button
        style={{...estilos.boton,backgroundColor:"#0d6efd",color:"white"}}
        onClick={() => {
            setMetodoActivo("cascada");
            setMostrarModal(true);
        }}>
        CASCADA
        </button>

        <button
        style={{...estilos.boton,backgroundColor:"#6c757d",color:"white"}}
        onClick={() => {
            setMetodoActivo("modelo_v");
            setMostrarModal(true);
        }}>
        MODELO V
        </button>

        <button
        style={{...estilos.boton,backgroundColor:"#198754",color:"white"}}
        onClick={() => {
            setMetodoActivo("agiles");
            setMostrarModal(true);
        }}>
        ÁGILES
        </button>
        
        <button
        style={{...estilos.boton,backgroundColor:"#dc3545",color:"black"}}
        onClick={() => {
            setMetodoActivo("scrum");
            setMostrarModal(true);
        }}>
        SCRUM
        </button>

        <button
        style={{...estilos.boton,backgroundColor:"#ffc107",color:"white"}}
        onClick={() => {
            setMetodoActivo("kanban");
            setMostrarModal(true);
        }}>
        KANBAN
        </button>

        <button
        style={{...estilos.boton,backgroundColor:"#0dcaf0",color:"white"}}
        onClick={() => {
            setMetodoActivo("xp");
            setMostrarModal(true);
        }}>
        XP
        </button>

        <button
        style={{...estilos.boton,backgroundColor:"#212529",color:"white"}}
        onClick={() => {
            setMetodoActivo("hibridas");
            setMostrarModal(true);
        }}>
        HÍBRIDAS
        </button>
      
        {mostrarModal && metodoActivo && (
        <div style={estilos.modalOverlay} onClick={cerrarModal}>
            <div
            style={estilos.contenidoModal}
            onClick={(e) => e.stopPropagation()}
            >
            <span style={estilos.cerrarX} onClick={cerrarModal}>
                ✖
            </span>

            <h2>{informacion[metodoActivo].titulo}</h2>

            <img
                src={informacion[metodoActivo].imagen}
                alt={informacion[metodoActivo].titulo}
                style={{ width: "100%", borderRadius: "8px", marginTop: "10px" }}
            />

            </div>
        </div>
        )}
        <br/>
        <hr style={{marginTop:100}}></hr>
        <h2>LINK A TABLERO DE TRABAJO</h2>
        <a
        className="App-link"
        href="https://josechrz.atlassian.net/jira/software/projects/KAN/boards/1"
        target="_blank"
        rel="noopener noreferrer"
        >
            <button style={{
                ...estilos.botonAzul,
                backgroundColor: hovered==="jira"  ? '#0b5ed7' : 'white',
                color:hovered==="jira" ? "white":'#0b5ed7',
                transition: 'all 0.3s ease'}}
                onMouseEnter={() => setHovered("jira")}
                onMouseLeave={() => setHovered(null)}>
                    ---- JIRA ----
                    </button>
        </a>
        <br/>
        <hr style={{marginTop:100}}></hr>
        <button style={{
            ...estilos.botonAzul,
            backgroundColor: hovered === "regresar" ? '#0b5ed7' : 'white',
            color:hovered === "regresar" ? "white":'#0b5ed7',
            transition: 'all 0.3s ease'}}
            onMouseEnter={() => setHovered("regresar")}
            onMouseLeave={() => setHovered(null)}
            onClick={()=>navigate("/")}>REGRESAR MÉNU PRINCIPAL</button>
        <br></br>
        <br></br>
        <h2>FRASE: "CAMARON QUE SE DUERME... SE LO LLEVA LA CORRIENTE"</h2>
        <br></br>
        <h2>ALUMNO: JOSE ANGEL RODRIGUEZ CHAIREZ</h2>
        <br></br>
        <hr></hr>
    </div>
  );
};

export default Parcial2;